# ---------- 4. AI integration: HYBRID ----------
def _ai_fallback(prediction, temp_val, appliance_val):
    if prediction == 1:
        return (f"[AI - offline mode] ANOMALOUS consumption detected. "
                f"Temperature {temp_val} degrees, total appliance load {appliance_val} kW. "
                f"Suggest checking heating/cooling equipment or a possible power leak.")
    return (f"[AI - offline mode] NORMAL consumption at temperature "
            f"{temp_val} degrees, total appliance load {appliance_val} kW. No signs of anomaly.")


def get_ai_explanation(prediction, temp_val, appliance_val):
    if not GEMINI_API_KEY:
        return _ai_fallback(prediction, temp_val, appliance_val)

    label = "ANOMALOUS" if prediction == 1 else "NORMAL"
    prompt = (
        "You are a smart home energy analysis assistant. "
        f"The model has just classified the power consumption as {label}. "
        f"Context: temperature {temp_val} degrees, total appliances on {appliance_val} kW. "
        "Briefly explain (3-4 sentences) in English why this might be the case "
        "and suggest an action for the user."
    )
    try:
        import requests
        url = ("https://generativelanguage.googleapis.com/v1beta/models/"
               "gemini-2.5-flash-lite:generateContent?key=" + GEMINI_API_KEY)
        resp = requests.post(
            url,
            json={"contents": [{"parts": [{"text": prompt}]}]},
            timeout=15,
        )
        resp.raise_for_status()
        text = resp.json()["candidates"][0]["content"]["parts"][0]["text"]
        return "[AI - Gemini] " + text.strip()
    except Exception as e:
        return _ai_fallback(prediction, temp_val, appliance_val) + f"  (Fallback reason: {e})"


# ---------- 5. Correct prediction function ----------
def predict_anomaly(user_inputs: dict):
    """Return (class, probability/score) using the calibrated validation threshold."""
    if model is None or feature_columns is None:
        temp = float(user_inputs.get("temperature", 0) or 0)
        appl = float(user_inputs.get("total_appliance", 0) or 0)
        pred = 1 if (temp > 80 or appl > 5) else 0
        return pred, float(pred)

    complete = dict(feature_defaults)
    complete.update({k: v for k, v in user_inputs.items() if v is not None})
    row = pd.DataFrame([complete]).reindex(columns=feature_columns)
    if row.isna().any().any():
        missing = row.columns[row.isna().any()].tolist()
        raise ValueError(f"Missing values for features: {missing}")
    if hasattr(model, "predict_proba"):
        score = float(model.predict_proba(row)[:, 1][0])
    else:
        score = float(model.decision_function(row)[0])
    return int(score >= decision_threshold), score


