def build_recommendations(top5_df, corr_daily):
    recs = []
    if not top5_df.empty:
        top_name = top5_df.index[0]
        top_share = top5_df["Share_%"].iloc[0] if "Share_%" in top5_df.columns else None
        if top_share is not None:
            recs.append(f"{top_name} accounts for {top_share}% of total appliance consumption - "
                        f"the top priority for saving power is adjusting this device's operating "
                        f"schedule (e.g., timers, adjusting the set temperature).")
        if "Peak_Hour" in top5_df.columns:
            ph = top5_df["Peak_Hour"].iloc[0]
            recs.append(f"{top_name} runs most heavily around {ph}:00 - "
                        f"part of its operation could be shifted to off-peak hours to reduce load.")

    if isinstance(corr_daily, pd.DataFrame) and "gen [kW]" in corr_daily.columns:
        gen_corr = corr_daily["gen [kW]"].dropna()
        if "temperature" in gen_corr.index:
            recs.append(f"Solar generation correlates with temperature (r={gen_corr['temperature']:.2f}) "
                        f"- high-power appliances should be used as much as possible on warm, sunny "
                        f"days to draw directly from solar power and reduce grid usage.")
        if "cloudCover" in gen_corr.index and gen_corr["cloudCover"] < 0:
            recs.append("Higher cloud cover reduces solar generation - "
                        "the system should automatically switch to an 'energy-saving priority' "
                        "alert on cloudy days.")

    recs.append("Set up automatic scheduling: shift the Dishwasher/Microwave to off-peak hours "
               "(nighttime or midday when sunny) to reduce peak-hour electricity costs.")
    recs.append("When the system reports repeated anomaly alerts from a single device, "
               "send a Smart City notification so the user can inspect the device (risk of "
               "malfunction/electrical leakage).")
    return recs[:6]


recommendations = build_recommendations(top5_df, corr_daily)


